public HttpForm buildRequestHttpForm(GatewayRequestMetaDataConf metaDataConf) {

        AgosPaymentRequest agosPaymentRequest = buildExternalChannelRequest(metaDataConf);

        ChannelGatewayAPI channelGatewayAPI = metaDataConf.getGatewayApi();
        String encoding = channelGatewayAPI.getApiEncoding();


        Map<String, String> agosPaymentRequestMap = AnnotationUtil.parseField(agosPaymentRequest);

        HttpForm httpForm = new HttpForm(channelGatewayAPI.getApiURL(), agosPaymentRequestMap);
        httpForm.setCharset(encoding);
        httpForm.setSubmitMethod(RequestMethod.POST.name());

        return httpForm;  解析一下代码

public HttpForm executeWebMethod(){
        IChannelHttpFormBuilder httpFormBuilder =
                ChannelHttpFormBuilderFactory.getBuilderInstance(metaDataConf.getGatewayApi().getApiCode());

        if (httpFormBuilder == null) {
            throw ExceptionUtils.buildHonorPayException(PayErrorCodeEnum.SYS_EX.getCode(), "Can not find IChannelHttpFormBuilder!");
        }

        return httpFormBuilder.buildRequestHttpForm(metaDataConf);
    }
