            return (ChannelGatewayAPI) getParameter(GATEWAY_API);
        }
        // find ChannelGatewayAPI
        ChannelGatewayQueryFragment gatewayQueryFragment = SpringBeansUtil.getBean(ChannelGatewayQueryFragment.class);
