public ChannelGatewayAPI queryGatewayApi(ChannelRouteRequest routeRequest) {

        String paySource = StringUtil.isEmpty(routeRequest.getPaySource()) ? null : PaySourceEnum.getEnum(routeRequest.getPaySource()).getType();


        List<ChannelGatewayConfigVo> gatewayConfigs =
                gatewayDataAccessService.selectByBankMerchantNo(routeRequest.getBankMerchantNo(),
                        routeRequest.getChannelCode(), routeRequest.getBankType(), routeRequest.getActionType(), paySource);

        if (CollectionUtils.isEmpty(gatewayConfigs)) {
            gatewayConfigs = gatewayDataAccessService.selectByBankCode(routeRequest.getChannelCode(), routeRequest.getBankType(), routeRequest.getActionType());
        }

        if (gatewayConfigs.size() == 1) {
            return convertTo(gatewayConfigs.get(0));
        }

        Map<String, ChannelGatewayConfigVo> gatewayConfigsMap = new HashMap<>();
        gatewayConfigs.forEach(item -> {
            String key =
                    item.getBankCode() + "$" + item.getBankType() + "$" + item.getBranchBankCode() + "$" + item.getPaySource();
            gatewayConfigsMap.put(key, item);
        });

        String matchKey =
                routeRequest.getChannelCode() + "$" + routeRequest.getBankType() + "$" + null + "$" + paySource;
        ChannelGatewayConfigVo matchedConfig = gatewayConfigsMap.get(matchKey);
        if (matchedConfig == null) {
            // 按gateway中paySource为null适用于多种场景的情况, 再匹配一次
            matchKey = routeRequest.getChannelCode() + "$" + routeRequest.getBankType() + "$" + null + "$" + null;
            matchedConfig = gatewayConfigsMap.get(matchKey);
        }

        if (matchedConfig == null) {
            throw ExceptionUtils.buildHonorPayException(PayErrorCodeEnum.CHANNEL_GATEWAY_NOT_FUND.getCode(), "no gateway interface configured");
        }
        return convertTo(matchedConfig);
    }

